<?php

declare(strict_types=1);

$page = $_GET['page'] ?? 'home';
$page = trim($page, '/');

if ($page === '') {
    $page = 'home';
}

if (!preg_match('/^[a-zA-Z0-9_-]+$/', $page)) {
    http_response_code(400);
    exit('Invalid page.');
}

